<?php namespace App\Repositories\Student;use App\Repositories\BaseRepository;use App\Models\Student\StudentGroup;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class StudentGroupRepository extends BaseRepository{    public function __construct(StudentGroup $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByName(string $name): ?StudentGroup    {        return $this->query()->where('name', $name)->first();    }    public function getActiveGroups(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getGroupWithMembers(int $groupId): ?StudentGroup    {        return $this->query()->with('members')->findOrFail($groupId);    }    public function countMembersByGroup(): Collection    {        return $this->query()->withCount('members')->get();    }    public function findByType(string $type): Collection    {        return $this->findByField('type', $type);    }    public function searchGroups(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }}